import { gunzipSync } from "node:zlib";

export type OfficialSourceFeature = {
  title: string;
  description?: string;
  image?: string;
};

export type OfficialSourceResource = {
  title: string;
  url: string;
};

export type OfficialSourceProductDetail = {
  sourceUrl: string;
  title: string;
  subtitle?: string;
  heroImage?: string;
  overviewHeading?: string;
  overviewParas?: string[];
  overviewImage?: string;
  technical?: Array<{ label: string; value: string }>;
  features?: OfficialSourceFeature[];
  resources?: OfficialSourceResource[];
};

const encodedOfficialProductDetails = "";

export const officialSourceProductGroups = JSON.parse(
  gunzipSync(Buffer.from(encodedOfficialProductDetails, "base64")).toString("utf8"),
) as Record<string, OfficialSourceProductDetail[]>;

